```ts
export function makeColumnMesh(
  col: Extract<Element, { kind: 'column' }>,
  elevM: number,
  paint: ViewportPaintBundle | null,
): THREE.Mesh {
  const bM = THREE.MathUtils.clamp((col.bMm ?? 300) / 1000, 0.05, 2);
  const hM = THREE.MathUtils.clamp((col.hMm ?? 300) / 1000, 0.05, 2);
  const baseOff = (col.baseConstraintOffsetMm ?? 0) / 1000;
  const topOff = col.topConstraintOffsetMm != null ? col.topConstraintOffsetMm / 1000 : 0;
  const heightM = col.heightMm != null ? THREE.MathUtils.clamp(col.heightMm / 1000, 0.25, 40) : 3.0;
  const yBase = elevM + baseOff;
  const posX = col.positionMm.xMm / 1000;
  const posZ = col.positionMm.yMm / 1000;

  const topOffX = (col.topOffsetXMm ?? 0) / 1000;
  const topOffZ = (col.topOffsetYMm ?? 0) / 1000;

  const mat = makeThreeMaterialForKey(col.materialKey, {
    usage: 'structural',
    fallbackColor: categoryColorOr(paint, 'wall'),
    fallbackRoughness: paint?.categories.wall.roughness ?? 0.8,
    fallbackMetalness: paint?.categories.wall.metalness ?? 0,
  });

  if (Math.abs(topOffX) < 1e-6 && Math.abs(topOffZ) < 1e-6) {
    // Vertical column (existing behavior)
    const geo = new THREE.BoxGeometry(bM, heightM, hM);
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.set(posX, yBase + heightM / 2 + topOff, posZ);
    mesh.rotation.y = THREE.MathUtils.degToRad(col.rotationDeg ?? 0);
    addEdges(mesh);
    return mesh;
  }

  // Inclined column — direction from base to top
  const baseVec = new THREE.Vector3(posX, yBase, posZ);
  const topVec = new THREE.Vector3(posX + topOffX, yBase + heightM, posZ + topOffZ);
  const dir = new THREE.Vector3().subVectors(topVec, baseVec);
  const actualLen = dir.length();
  dir.normalize();

  const geo = new THREE.BoxGeometry(bM, actualLen, hM);
  const mesh = new THREE.Mesh(geo, mat);

  // Midpoint position
  const mid = new THREE.Vector3().addVectors(baseVec, topVec).multiplyScalar(0.5);
  mesh.position.copy(mid);

  // Align local Y axis (box height) to dir
  const up = new THREE.Vector3(0, 1, 0);
  const quaternion = new THREE.Quaternion().setFromUnitVectors(up, dir);
  mesh.quaternion.copy(quaternion);

  addEdges(mesh);
  return mesh;
}
```

