import { describe, expect, it } from 'vitest';
import * as THREE from 'three';
import { makeColumnMesh } from './meshBuilders';
import type { Element } from '@bim-ai/core';

type ColElem = Extract<Element, { kind: 'column' }>;

const BASE_COL: ColElem = {
  kind: 'column',
  id: 'col-1',
  name: 'C1',
  levelId: 'lvl-1',
  positionMm: { xMm: 0, yMm: 0 },
  bMm: 300,
  hMm: 300,
  heightMm: 3000,
};

describe('makeColumnMesh — sloped column', () => {
  it('creates a vertical mesh when no offset is set', () => {
    const mesh = makeColumnMesh(BASE_COL, 0, null);
    expect(mesh).toBeInstanceOf(THREE.Mesh);
    expect(mesh.position.y).toBeCloseTo(1.5, 5);
  });

  it('tilts the column when topOffsetXMm is non-zero', () => {
    const col: ColElem = { ...BASE_COL, id: 'col-sloped', topOffsetXMm: 500 };
    const mesh = makeColumnMesh(col, 0, null);
    expect(mesh).toBeInstanceOf(THREE.Mesh);
    // Midpoint X should be shifted by half the offset
    expect(mesh.position.x).toBeCloseTo(0.25, 4);
  });

  it('positions sloped column midpoint at 500mm X offset correctly', () => {
    const col: ColElem = { ...BASE_COL, id: 'col-x', topOffsetXMm: 500 };
    const mesh = makeColumnMesh(col, 0, null);
    // Base at x=0, top at x=0.5, mid at x=0.25
    expect(mesh.position.x).toBeCloseTo(0.25, 4);
    expect(mesh.position.y).toBeCloseTo(1.5, 4);
  });

  it('column with both X and Z offset produces non-identity quaternion', () => {
    const col: ColElem = { ...BASE_COL, id: 'col-xy', topOffsetXMm: 500, topOffsetYMm: 300 };
    const mesh = makeColumnMesh(col, 0, null);
    const q = mesh.quaternion;
    // Not the identity quaternion
    expect(Math.abs(q.w)).toBeLessThan(1 - 1e-6);
  });
});

